# 对话备份脚本 - 备份 OpenClaw 会话记录到 Markdown
# 用法：.\backup-conversations.ps1 -OutputDir "./conversation-backup"

param(
    [string]$OutputDir = "./conversation-backup",
    [int]$DaysBack = 7
)

# 会话记录路径
$SessionsPath = "C:\Users\Administrator\.openclaw\agents\main\sessions"

# 创建输出目录
if (!(Test-Path $OutputDir)) {
    New-Item -ItemType Directory -Path $OutputDir | Out-Null
}

# 获取最近的会话文件
$sessionFiles = Get-ChildItem $SessionsPath -Filter "*.jsonl" | 
    Sort-Object LastWriteTime -Descending | 
    Select-Object -First 20

Write-Host "找到 $($sessionFiles.Count) 个会话文件"

# 转换 JSONL 为 Markdown
foreach ($sessionFile in $sessionFiles) {
    Write-Host "处理：$($sessionFile.Name)"

    $content = Get-Content $sessionFile.FullName -Raw | ConvertFrom-Json -AsArray

    $markdown = "# 对话记录 - $($sessionFile.BaseName)`n`n"
    $markdown += "**备份时间：** $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')`n`n"
    $markdown += "---`n`n"

    foreach ($msg in $content) {
        $timestamp = [DateTimeOffset]::FromUnixTimeMilliseconds($msg.timestamp).DateTime.ToString('yyyy-MM-dd HH:mm:ss')

        if ($msg.role -eq "user") {
            $markdown += "### 👤 主人 `[$timestamp]` `n`n"
            foreach ($item in $msg.content) {
                if ($item.type -eq "text") {
                    $markdown += "$($item.text)`n`n"
                }
            }
        } elseif ($msg.role -eq "assistant") {
            $markdown += "### 🦞 龙虾 `[$timestamp]` `n`n"
            foreach ($item in $msg.content) {
                if ($item.type -eq "text") {
                    $markdown += "$($item.text)`n`n"
                }
            }
        }

        $markdown += "---`n`n"
    }

    # 保存 Markdown 文件
    $outputFile = Join-Path $OutputDir "$($sessionFile.BaseName).md"
    $markdown | Out-File -FilePath $outputFile -Encoding utf8
    Write-Host "  → 已保存：$outputFile"
}

Write-Host "`n✅ 备份完成！"

