// 第一个 Remotion 视频 - 文字动画示例
import {AbsoluteFill, useCurrentFrame, spring} from 'remotion';

export function MyFirstVideo() {
  const frame = useCurrentFrame();

  // 文字淡入效果
  const opacity = spring({
    frame,
    fps: 30,
    durationInFrames: 60
  });

  // 文字上移效果
  const translateY = spring({
    frame,
    fps: 30,
    durationInFrames: 60,
    from: 50,
    to: 0
  });

  return (
    <AbsoluteFill style={{
      backgroundColor: '#1a1a2e',
      justifyContent: 'center',
      alignItems: 'center'
    }}>
      <h1 style={{
        color: '#e94560',
        fontSize: '80px',
        opacity,
        transform: `translateY(${translateY}px)`,
        textAlign: 'center'
      }}>
        你好，Remotion!
      </h1>
      <p style={{
        color: '#ffffff',
        fontSize: '30px',
        marginTop: '20px',
        opacity: opacity * 0.8
      }}>
        我的第一个编程视频 🎬
      </p>
    </AbsoluteFill>
  );
}

export default MyFirstVideo;

import {Config} from '@remotion/cli/config';

Config.setVideoImageFormat('jpeg');
Config.setOverwriteOutput(true);

// Remotion 入口文件
import {registerRoot} from 'remotion';
import {MyFirstVideo} from './MyFirstVideo.jsx';

// 注册视频组件
registerRoot(() => {
  return {
    id: 'my-first-video',
    component: MyFirstVideo,
    durationInFrames: 150,  // 5 秒 @ 30fps
    fps: 30,
    width: 1920,
    height: 1080
  };
});

